"use client";

import { useEffect, useState } from "react";

import { apiFetch } from "@/lib/api";
import { isSuperAdmin } from "@/lib/auth";

import CustomersTable from "./CustomersTable";
import CustomerModal from "./CustomerModal";

export type Customer = {
  id: string;
  full_name_ar: string;
  full_name_en?: string;
  mobile_number: string;
  national_id?: string;
  city?: string;
  address?: string;
  risk_level?: string;
  status?: string;
};

export type CustomerForm = {
  full_name_ar: string;
  full_name_en: string;
  mobile_number: string;
  national_id: string;
  city: string;
  address: string;
};

const emptyForm: CustomerForm = {
  full_name_ar: "",
  full_name_en: "",
  mobile_number: "",
  national_id: "",
  city: "",
  address: "",
};

export default function CustomersClient() {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const [page, setPage] = useState(1);
  const pageSize = 15;

  const [editingCustomer, setEditingCustomer] =
    useState<Customer | null>(null);

  const [isModalOpen, setIsModalOpen] = useState(false);

  const [superAdmin, setSuperAdmin] = useState(false);

  const [form, setForm] =
    useState<CustomerForm>(emptyForm);

  useEffect(() => {
    loadCustomers();
    setSuperAdmin(isSuperAdmin());
  }, []);

  async function loadCustomers() {
    try {
      setLoading(true);
      setError("");

      const data = await apiFetch("/merchant/customers");

      setCustomers(data);
    } catch (err: any) {
      setError(err.message || "Unable to load customers");
    } finally {
      setLoading(false);
    }
  }

  function openAddModal() {
    setEditingCustomer(null);
    setForm(emptyForm);
    setIsModalOpen(true);
  }

  function openEditModal(customer: Customer) {
    setEditingCustomer(customer);

    setForm({
      full_name_ar: customer.full_name_ar || "",
      full_name_en: customer.full_name_en || "",
      mobile_number: customer.mobile_number || "",
      national_id: customer.national_id || "",
      city: customer.city || "",
      address: customer.address || "",
    });

    setIsModalOpen(true);
  }

  async function saveCustomer(e: React.FormEvent) {
    e.preventDefault();

    try {
      if (editingCustomer) {
        await apiFetch(
          `/merchant/customers/${editingCustomer.id}`,
          {
            method: "PATCH",
            body: JSON.stringify(form),
          }
        );
      } else {
        await apiFetch("/merchant/customers", {
          method: "POST",
          body: JSON.stringify(form),
        });
      }

      setIsModalOpen(false);
      setEditingCustomer(null);
      setForm(emptyForm);

      loadCustomers();
    } catch (err: any) {
      setError(err.message);
    }
  }

  async function deactivateCustomer(id: string) {
    if (!confirm("Deactivate this customer?")) return;

    try {
      await apiFetch(`/merchant/customers/${id}`, {
        method: "DELETE",
      });

      loadCustomers();
    } catch (err: any) {
      setError(err.message);
    }
  }

  const totalPages = Math.ceil(customers.length / pageSize);

  const paginatedCustomers = customers.slice(
    (page - 1) * pageSize,
    page * pageSize
  );

  return (
    <>
      {/* top toolbar */}

      <div className="mb-5 flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold text-gray-800 dark:text-white/90">
            Customer Records
          </h2>

          <p className="text-sm text-gray-500 dark:text-gray-400">
            View, add and manage customers.
          </p>
        </div>

        <button
          onClick={openAddModal}
          className="rounded-lg bg-brand-500 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-600"
        >
          Add Customer
        </button>
      </div>

      {error && (
        <div className="mb-5 rounded-lg border border-error-200 bg-error-50 px-4 py-3 text-sm text-error-700">
          {error}
        </div>
      )}

      <CustomersTable
        customers={paginatedCustomers}
        loading={loading}
        page={page}
        totalPages={totalPages}
        onPageChange={setPage}
        onEdit={openEditModal}
        onDeactivate={deactivateCustomer}
      />

      <CustomerModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        editingCustomer={editingCustomer}
        form={form}
        setForm={setForm}
        onSubmit={saveCustomer}
        superAdmin={superAdmin}
      />
    </>
  );
}